import React, { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';
import { fetchMyAccounts } from '../../store/slices/accountSlice';
import { transferSchema, depositSchema, withdrawSchema } from '../../schemas';

export default function TransferPage() {
  const dispatch = useDispatch();
  const { accounts } = useSelector(s => s.accounts);
  const [beneficiaries, setBeneficiaries] = useState([]);
  const [activeTab, setActiveTab] = useState('transfer');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    dispatch(fetchMyAccounts());
    axiosInstance.get('/beneficiaries/my').then(r => setBeneficiaries(r.data.beneficiaries || []));
  }, [dispatch]);

  const activeAccounts = accounts.filter(a => a.status === 'ACTIVE');
  const savingsAcc = activeAccounts.find(a => a.accountType === 'SAVINGS');

  const transferFormik = useFormik({
    initialValues: { fromAccountNumber: savingsAcc?.accountNumber || '', toAccountNumber: '', amount: '', description: '' },
    validationSchema: transferSchema,
    enableReinitialize: true,
    onSubmit: async (values, { resetForm }) => {
      setLoading(true);
      try {
        await axiosInstance.post('/transactions/transfer', values);
        toast.success('Transfer successful!');
        dispatch(fetchMyAccounts());
        resetForm();
      } catch (err) { toast.error(err.response?.data?.message || 'Transfer failed'); }
      finally { setLoading(false); }
    }
  });

  const depositFormik = useFormik({
    initialValues: { accountNumber: savingsAcc?.accountNumber || '', amount: '', description: '' },
    validationSchema: depositSchema,
    enableReinitialize: true,
    onSubmit: async (values, { resetForm }) => {
      setLoading(true);
      try {
        await axiosInstance.post('/transactions/deposit', values);
        toast.success('Deposit successful!');
        dispatch(fetchMyAccounts());
        resetForm();
      } catch (err) { toast.error(err.response?.data?.message || 'Deposit failed'); }
      finally { setLoading(false); }
    }
  });

  const withdrawFormik = useFormik({
    initialValues: { accountNumber: savingsAcc?.accountNumber || '', amount: '', description: '' },
    validationSchema: withdrawSchema,
    enableReinitialize: true,
    onSubmit: async (values, { resetForm }) => {
      setLoading(true);
      try {
        await axiosInstance.post('/transactions/withdraw', values);
        toast.success('Withdrawal successful!');
        dispatch(fetchMyAccounts());
        resetForm();
      } catch (err) { toast.error(err.response?.data?.message || 'Withdrawal failed'); }
      finally { setLoading(false); }
    }
  });

  const inp = { padding: '10px 14px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, width: '100%', boxSizing: 'border-box', marginBottom: 12 };
  const tabStyle = (active) => ({ padding: '10px 24px', border: 'none', borderRadius: 8, cursor: 'pointer', fontWeight: 600, background: active ? '#3b82f6' : '#fff', color: active ? '#fff' : '#64748b' });

  const AccSelect = ({ formik, fieldName = 'accountNumber' }) => (
    <select style={inp} {...formik.getFieldProps(fieldName)}>
      {activeAccounts.map(a => <option key={a.accountNumber} value={a.accountNumber}>{a.accountType} — {a.accountNumber} (₹{a.balance?.toLocaleString('en-IN')})</option>)}
    </select>
  );

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 style={{ margin: '0 0 24px', color: '#1e293b' }}> Transactions</h2>
      </div>

      <div className="d-flex flex-wrap gap-2 mb-4">
        {['transfer', 'deposit', 'withdraw'].map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)} style={tabStyle(activeTab === tab)}>
            {tab === 'transfer' ? '↔️ Transfer' : tab === 'deposit' ? '⬇️ Deposit' : '⬆️ Withdraw'}
          </button>
        ))}
      </div>

      <div className="row">
        <div className="col-12 col-md-8 col-lg-6 col-xl-5">
          <div style={{ background: '#fff', borderRadius: 12, padding: 28, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            {activeTab === 'deposit' && (
              <form onSubmit={depositFormik.handleSubmit}>
                <label style={{ fontSize: 13, fontWeight: 600 }}>Account</label>
                <AccSelect formik={depositFormik} />
                <label style={{ fontSize: 13, fontWeight: 600 }}>Amount (₹)</label>
                <input type="number" style={inp} placeholder="Enter amount" {...depositFormik.getFieldProps('amount')} />
                <label style={{ fontSize: 13, fontWeight: 600 }}>Description</label>
                <input type="text" style={inp} placeholder="e.g. Salary Credit" {...depositFormik.getFieldProps('description')} />
                <button type="submit" disabled={loading} style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>
                  {loading ? 'Processing...' : 'Deposit'}
                </button>
              </form>
            )}
            {activeTab === 'withdraw' && (
              <form onSubmit={withdrawFormik.handleSubmit}>
                <label style={{ fontSize: 13, fontWeight: 600 }}>Account</label>
                <AccSelect formik={withdrawFormik} />
                <label style={{ fontSize: 13, fontWeight: 600 }}>Amount (₹)</label>
                <input type="number" style={inp} placeholder="Enter amount" {...withdrawFormik.getFieldProps('amount')} />
                <button type="submit" disabled={loading} style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>
                  {loading ? 'Processing...' : 'Withdraw'}
                </button>
              </form>
            )}
            {activeTab === 'transfer' && (
              <form onSubmit={transferFormik.handleSubmit}>
                <label style={{ fontSize: 13, fontWeight: 600 }}>From Account</label>
                <AccSelect formik={transferFormik} fieldName="fromAccountNumber" />
                <label style={{ fontSize: 13, fontWeight: 600 }}>To Account Number</label>
                <input type="text" style={inp} placeholder="Recipient account number" {...transferFormik.getFieldProps('toAccountNumber')} />
                {beneficiaries.filter(b => b.status === 'ACTIVE').length > 0 && (
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 13, fontWeight: 600 }}>Or select beneficiary</label>
                    <select style={inp} onChange={e => transferFormik.setFieldValue('toAccountNumber', e.target.value)}>
                      <option value="">-- Select --</option>
                      {beneficiaries.filter(b => b.status === 'ACTIVE').map(b => (
                        <option key={b.beneficiaryId} value={b.accountNumber}>{b.beneficiaryName} — {b.accountNumber}</option>
                      ))}
                    </select>
                  </div>
                )}
                <label style={{ fontSize: 13, fontWeight: 600 }}>Amount (₹)</label>
                <input type="number" style={inp} placeholder="Enter amount" {...transferFormik.getFieldProps('amount')} />
                <label style={{ fontSize: 13, fontWeight: 600 }}>Description</label>
                <input type="text" style={inp} placeholder="e.g. Transfer to Rahul" {...transferFormik.getFieldProps('description')} />
                <button type="submit" disabled={loading} style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>
                  {loading ? 'Processing...' : 'Send Money'}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
}
